from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Get the main subject from the first triple
    main_subject = triples[0].subject

    # Create a mapping of predicates to their values
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    # Build sentence parts
    parts = []

    # Start with main identity
    if 'nationality' in predicate_map:
        parts.append(f"{main_subject}, a {predicate_map['nationality'][0]} politician")
    elif 'profession' in predicate_map:
        parts.append(f"{main_subject}, a {predicate_map['profession'][0]}")
    else:
        parts.append(main_subject)

    # Build the main clause with key information
    clauses = []

    # Birth info
    if 'birthDate' in predicate_map or 'birthYear' in predicate_map or 'birthPlace' in predicate_map:
        birth_info = []
        if 'birthDate' in predicate_map:
            birth_info.append(f"born on {predicate_map['birthDate'][0]}")
        elif 'birthYear' in predicate_map:
            birth_info.append(f"born in {predicate_map['birthYear'][0]}")
        if 'birthPlace' in predicate_map:
            birth_info.append(f"in {predicate_map['birthPlace'][0]}")
        if birth_info:
            clauses.append(f"who was {' '.join(birth_info)}")

    # Career info
    if 'office' in predicate_map:
        clauses.append(f"served as {predicate_map['office'][0]}")
    if 'party' in predicate_map:
        clauses.append(f"with the {predicate_map['party'][0]} party")

    # Country/State info
    if 'country' in predicate_map:
        clauses.append(f"from {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        clauses.append(f"in {predicate_map['state'][0]}")

    # Military info
    if 'militaryBranch' in predicate_map:
        clauses.append(f"and served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        clauses.append(f"holding the rank of {predicate_map['militaryRank'][0]}")

    # Death info
    if 'deathDate' in predicate_map or 'deathYear' in predicate_map or 'deathPlace' in predicate_map:
        death_info = []
        if 'deathDate' in predicate_map:
            death_info.append(f"died on {predicate_map['deathDate'][0]}")
        elif 'deathYear' in predicate_map:
            death_info.append(f"died in {predicate_map['deathYear'][0]}")
        if 'deathPlace' in predicate_map:
            death_info.append(f"in {predicate_map['deathPlace'][0]}")
        if death_info:
            clauses.append(f"and {' '.join(death_info)}")

    # Other info
    if 'almaMater' in predicate_map:
        clauses.append(f"and studied at {predicate_map['almaMater'][0]}")
    if 'spouse' in predicate_map:
        clauses.append(f"and was married to {predicate_map['spouse'][0]}")
    if 'predecessor' in predicate_map:
        clauses.append(f"and was preceded by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        clauses.append(f"and was succeeded by {predicate_map['successor'][0]}")
    if 'award' in predicate_map:
        clauses.append(f"and received the {predicate_map['award'][0]}")
    if 'religion' in predicate_map:
        clauses.append(f"and was a {predicate_map['religion'][0]}")
    if 'battle' in predicate_map:
        clauses.append(f"and participated in the {predicate_map['battle'][0]}")
    if 'residence' in predicate_map:
        clauses.append(f"with residence at {predicate_map['residence'][0]}")
    if 'activeYearsStartDate' in predicate_map:
        clauses.append(f"starting in {predicate_map['activeYearsStartDate'][0]}")
    if 'activeYearsEndDate' in predicate_map:
        clauses.append(f"until {predicate_map['activeYearsEndDate'][0]}")

    # Combine all clauses into one sentence
    if clauses:
        result = parts[0] + " " + ", ".join(clauses)
    else:
        result = parts[0].rstrip(",")

    return result + "."

# EVOLVE-BLOCK-END

